import React, { useState } from 'react';

const App = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [models, setModels] = useState([
    { id: 1, name: 'Model 1', accuracy: 0.9, precision: 0.8 },
    { id: 2, name: 'Model 2', accuracy: 0.8, precision: 0.7 },
    { id: 3, name: 'Model 3', accuracy: 0.7, precision: 0.6 },
    { id: 4, name: 'Model 4', accuracy: 0.6, precision: 0.5 },
    { id: 5, name: 'Model 5', accuracy: 0.5, precision: 0.4 }
  ]);

  const handleSearch = (event) => {
    setSearchTerm(event.target.value);
  };

  const filteredModels = models.filter(model => model.name.toLowerCase().includes(searchTerm.toLowerCase()));

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#C06C88] p-4 rounded-lg">
        <input type="search" value={searchTerm} onChange={handleSearch} placeholder="Search AI Models" className="w-full p-2 rounded-lg bg-[#B7D7CD] text-black"/>
        <div className="grid grid-cols-5 gap-4 mt-4">
          {filteredModels.map(model => (
            <div key={model.id} className="bg-[#411C56] p-4 rounded-lg col-span-1">
              <p className="text-lg text-center">{model.name}</p>
              <p className="text-sm text-center">Accuracy: {model.accuracy.toFixed(2)}</p>
              <p className="text-sm text-center">Precision: {model.precision.toFixed(2)}</p>
            </div>
          ))}
        </div>
        <div className="bg-[#B7D7CD] p-4 rounded-lg mt-4">
          <p className="text-lg text-center">Performance Metrics</p>
          <div className="grid grid-cols-3 gap-4 mt-4">
            <div className="bg-[#FFFFFF] p-2 rounded-lg col-span-1">
              <p className="text-sm text-center">Accuracy</p>
              <p className="text-sm text-center">75%</p>
            </div>
            <div className="bg-[#FFFFFF] p-2 rounded-lg col-span-1">
              <p className="text-sm text-center">Precision</p>
              <p className="text-sm text-center">65%</p>
            </div>
            <div className="bg-[#FFFFFF] p-2 rounded-lg col-span-1">
              <p className="text-sm text-center">Chart</p>
              <p className="text-sm text-center">...</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;
